def categorize_article(title, description):
    title = str(title).lower()
    description = str(description).lower()
    if "sport" in title or "sport" in description or "sports" in title or "sports" in description:
        return "Sports"
    elif "business" in title or "business" in description or "economy" in title or "economy" in description or "finance" in title or "finance" in description:
        return "Business"
    elif "science" in title or "science" in description or "technology" in title or "technology" in description or "computer" in title or "computer" in description or "research" in title or "research" in description or "medical" in title or "medical" in description:
        return "Science/Technology"
    elif "world" in title or "world" in description or "politics" in title or "politics" in description or "government" in title or "government" in description:
        return "World"
    else:
        return None

def process_articles(articles, metadata):
    science_count = 0
    total_count = 0
    bad_articles = []
    for article in articles:
        try:
            article_id = int(article["article_id"])
        except (TypeError, ValueError) as e:
            bad_articles.append(article)
            continue

        if article_id in metadata:
            try:
                category = categorize_article(article.get("title", ""), article.get("description", ""))
            except Exception as e:
                print(f"Error categorizing article {article_id}: {type(e)}, {e}")
                category = None
            if category == "Science/Technology":
                science_count += 1
            total_count += 1
    print(f"Bad articles: {bad_articles!r}")
    return science_count, total_count

var_articles = json.loads(var_tool_query_db_X1gZlfd2wrOydIwiHYtG["query_db_response"]["result"])
var_metadata = [int(row["article_id"]) for row in json.loads(var_tool_query_db_Fsb9nPHaaaq7RgcwLOvi["query_db_response"]["result"])]

science_count, total_count = process_articles(var_articles, var_metadata)

if total_count > 0:
    fraction = float(science_count) / float(total_count)
else:
    fraction = 0.0

print("{\"fraction\": " + str(fraction) + "}")

